import type { ControlUiSkin } from "@/components/control-ui/skin";

/*
 * "Rig" is a THEME skin: brand lives in theme.css tokens (coral/near-black, --radius:0, grotesque)
 * + presentational skin.css. Config only names id, which scopes theme.css/skin.css — no per-slot
 * classes needed.
 */
export const skin: ControlUiSkin = { id: "rig" };

/*
 * "Rig" skin.css: pack's own vars + CSS cva recipes can't express (chamfer clip-path, corner
 * ticks, scanline, etc). Scoped to [data-skin="rig"] and layered so app utilities win.
 */

/* Pack's own vars, not part of theme.css contract; unlayered+scoped so @layer components below inherit them. */
[data-skin="rig"] {
  /* Diagonal corner cut: top-right + bottom-left. */
  --rig-chamfer: 9px;
}

@layer base {
  :root[data-skin="rig"] body {
    background:
      repeating-linear-gradient(
        0deg,
        oklch(from var(--foreground) l c h / 0.05) 0 1px,
        transparent 1px 4px
      ),
      var(--background);
  }
}

@layer components {
  /* ---- Controls: chamfer + motion ------------------------------------------------------------ */

  /* Squared + diagonal cut on two corners; clip-path removes border there, so outlined controls use
   * an inset ring instead. Hard offset shadow rides filter:drop-shadow (honors clip-path shape;
   * box-shadow would get clipped away). Resting=flat, hover=shadow, press=sink. */
  [data-skin="rig"] [data-control-ui][data-control="true"] {
    border: 0;
    border-radius: 0;
    clip-path: polygon(
      0 0,
      calc(100% - var(--rig-chamfer)) 0,
      100% var(--rig-chamfer),
      100% 100%,
      var(--rig-chamfer) 100%,
      0 calc(100% - var(--rig-chamfer))
    );
    box-shadow: none;
    text-shadow: none;
    font-weight: 600;
    letter-spacing: 0.01em;
    transition-property: transform, filter, background-color, color;
    transition-duration: var(--duration-fast);
    transition-timing-function: var(--ease-standard);
  }

  /* filter:drop-shadow paints RENDERED pixels — clean silhouette only on opaque solid fill; on
   * translucent surface/ghost/quiet it'd trace the GLYPHS, ghosting the label. Those variants get
   * nudge + brightness dip instead (brightness never offsets, can't duplicate). */
  [data-skin="rig"] [data-control-ui][data-control="true"]:hover {
    transform: translate(-1px, -1px);
  }

  [data-skin="rig"] [data-control-ui][data-control="true"]:active {
    transform: translate(1px, 1px);
    filter: brightness(0.94);
    transition-duration: 40ms;
  }

  /* Solid only: box-shadow can't survive clip-path, so uses drop-shadow (safe: box is opaque); :not(disabled) guard out-specifies the disabled reset. */
  [data-skin="rig"] [data-control-ui][data-control="true"][data-variant="solid"]:not(:disabled):not([data-disabled]):hover {
    filter: drop-shadow(3px 4px 0 oklch(from var(--foreground) l c h / 0.32));
  }

  [data-skin="rig"] [data-control-ui][data-control="true"][data-variant="solid"]:not(:disabled):not([data-disabled]):active {
    filter: drop-shadow(1px 1px 0 oklch(from var(--foreground) l c h / 0.4)) brightness(0.94);
  }

  [data-skin="rig"] [data-control-ui][data-control="true"]:disabled,
  [data-skin="rig"] [data-control-ui][data-control="true"][data-disabled] {
    transform: none;
    filter: none;
  }

  /* Solid = coral CTA; background-image sheen paints behind label (no z-index fight), chamfer still clips it. */
  [data-skin="rig"] [data-control-ui][data-control="true"][data-variant="solid"] {
    background-color: var(--primary);
    background-image: linear-gradient(180deg, oklch(1 0 0 / 0.14), transparent 46%);
    color: var(--primary-foreground);
  }

  [data-skin="rig"] [data-control-ui][data-control="true"][data-variant="solid"]:hover {
    background-image: linear-gradient(180deg, oklch(1 0 0 / 0.22), transparent 52%);
  }

  /* Outlined: hairline ink ring via inset shadow (clip-safe); faint fill, coral glow blooms on hover. */
  [data-skin="rig"] [data-control-ui][data-control="true"][data-variant="surface"],
  [data-skin="rig"] [data-control-ui][data-control="true"][data-variant="ghost"],
  [data-skin="rig"] [data-control-ui][data-control="true"][data-variant="quiet"] {
    background-color: oklch(from var(--foreground) l c h / 0.04);
    background-image: none;
    box-shadow: inset 0 0 0 1.5px oklch(from var(--foreground) l c h / 0.5);
  }

  [data-skin="rig"] [data-control-ui][data-control="true"][data-variant="surface"]:hover,
  [data-skin="rig"] [data-control-ui][data-control="true"][data-variant="ghost"]:hover,
  [data-skin="rig"] [data-control-ui][data-control="true"][data-variant="quiet"]:hover {
    background-color: oklch(from var(--foreground) l c h / 0.09);
    box-shadow:
      inset 0 0 0 1.5px var(--primary),
      inset 0 0 0 5px oklch(from var(--primary) l c h / 0.12);
  }

  /* ---- Chat: user bubble ---------------------------------------------------------------------- */

  /* User bubble = bg-primary coral both modes. Light: coral+near-black ink ~5.9:1 (fine). Dark:
   * cream ink on bright coral only ~3.5:1 (fails AA), so dark deepens coral fill enough for cream
   * to clear AA. */
  :is(.dark[data-skin="rig"], :where(.dark) [data-skin="rig"], [data-skin="rig"] :where(.dark))
    [data-control-ui="chat-message"][data-slot="content"][data-role="user"] {
    background-color: oklch(0.444 0.1277 32.246);
    color: oklch(0.9313 0.0143 81.504);
  }

  /* ---- Tabs ---------------------------------------------------------------------------------- */

  [data-skin="rig"] [data-control-ui="tabs"][data-slot="list"],
  [data-skin="rig"] [data-control-ui="tabs"][data-slot="tab"] {
    border-radius: 0;
  }

  [data-skin="rig"] [data-control-ui="tabs"][data-slot="tab"] {
    transition: color var(--duration-fast) var(--ease-standard);
  }

  [data-skin="rig"] [data-control-ui="tabs"][data-slot="tab"]:hover {
    color: var(--foreground);
  }

  [data-skin="rig"] [data-control-ui="tabs"][data-slot="indicator"] {
    border-radius: 0;
    background: var(--primary);
    box-shadow: 0 0 0 1px oklch(from var(--primary) l c h / 0.35);
  }

  /* ---- HUD corner ticks on the big framed surfaces ------------------------------------------- */

  /* Crosshair L-ticks in 4 corners: ::before=TL+BR, ::after=TR+BL, each a horiz+vert hairline; inset so they read despite overflow clipping. */
  [data-skin="rig"] [data-control-ui="chat-scene"][data-slot="root"],
  [data-skin="rig"] [data-control-ui="activity"][data-slot="root"][data-activity-kind="tool"],
  [data-skin="rig"] [data-control-ui="code-block-editor"][data-slot="root"],
  [data-skin="rig"] [data-control-ui="dialog"][data-slot="content"],
  [data-skin="rig"] [data-control-ui="chat-input"][data-slot="shell"] {
    position: relative;
    --rig-tick: 11px;
    --rig-tick-w: 1.5px;
    --rig-tick-inset: 7px;
    --rig-tick-c: oklch(from var(--primary) l c h / 0.6);
  }

  [data-skin="rig"] [data-control-ui="chat-scene"][data-slot="root"]::before,
  [data-skin="rig"] [data-control-ui="chat-scene"][data-slot="root"]::after,
  [data-skin="rig"] [data-control-ui="activity"][data-slot="root"][data-activity-kind="tool"]::before,
  [data-skin="rig"] [data-control-ui="activity"][data-slot="root"][data-activity-kind="tool"]::after,
  [data-skin="rig"] [data-control-ui="code-block-editor"][data-slot="root"]::before,
  [data-skin="rig"] [data-control-ui="code-block-editor"][data-slot="root"]::after,
  [data-skin="rig"] [data-control-ui="dialog"][data-slot="content"]::before,
  [data-skin="rig"] [data-control-ui="dialog"][data-slot="content"]::after,
  [data-skin="rig"] [data-control-ui="chat-input"][data-slot="shell"]::before,
  [data-skin="rig"] [data-control-ui="chat-input"][data-slot="shell"]::after {
    content: "";
    position: absolute;
    inset: var(--rig-tick-inset);
    pointer-events: none;
    z-index: 2;
  }

  /* ::before → top-left + bottom-right corners. */
  [data-skin="rig"] [data-control-ui="chat-scene"][data-slot="root"]::before,
  [data-skin="rig"] [data-control-ui="activity"][data-slot="root"][data-activity-kind="tool"]::before,
  [data-skin="rig"] [data-control-ui="code-block-editor"][data-slot="root"]::before,
  [data-skin="rig"] [data-control-ui="dialog"][data-slot="content"]::before,
  [data-skin="rig"] [data-control-ui="chat-input"][data-slot="shell"]::before {
    background:
      linear-gradient(var(--rig-tick-c), var(--rig-tick-c)) 0 0 / var(--rig-tick) var(--rig-tick-w) no-repeat,
      linear-gradient(var(--rig-tick-c), var(--rig-tick-c)) 0 0 / var(--rig-tick-w) var(--rig-tick) no-repeat,
      linear-gradient(var(--rig-tick-c), var(--rig-tick-c)) 100% 100% / var(--rig-tick) var(--rig-tick-w) no-repeat,
      linear-gradient(var(--rig-tick-c), var(--rig-tick-c)) 100% 100% / var(--rig-tick-w) var(--rig-tick) no-repeat;
  }

  /* ::after → top-right + bottom-left corners. */
  [data-skin="rig"] [data-control-ui="chat-scene"][data-slot="root"]::after,
  [data-skin="rig"] [data-control-ui="activity"][data-slot="root"][data-activity-kind="tool"]::after,
  [data-skin="rig"] [data-control-ui="code-block-editor"][data-slot="root"]::after,
  [data-skin="rig"] [data-control-ui="dialog"][data-slot="content"]::after,
  [data-skin="rig"] [data-control-ui="chat-input"][data-slot="shell"]::after {
    background:
      linear-gradient(var(--rig-tick-c), var(--rig-tick-c)) 100% 0 / var(--rig-tick) var(--rig-tick-w) no-repeat,
      linear-gradient(var(--rig-tick-c), var(--rig-tick-c)) 100% 0 / var(--rig-tick-w) var(--rig-tick) no-repeat,
      linear-gradient(var(--rig-tick-c), var(--rig-tick-c)) 0 100% / var(--rig-tick) var(--rig-tick-w) no-repeat,
      linear-gradient(var(--rig-tick-c), var(--rig-tick-c)) 0 100% / var(--rig-tick-w) var(--rig-tick) no-repeat;
  }

  /* Composer ticks light coral + frame on focus: "armed" state. */
  [data-skin="rig"] [data-control-ui="chat-input"][data-slot="shell"]:focus-within {
    --rig-tick-c: var(--primary);
    box-shadow: inset 0 0 0 1.5px oklch(from var(--primary) l c h / 0.55);
  }

  [data-skin="rig"] [data-control-ui="activity"][data-slot="root"][data-activity-kind="tool"][data-activity-state="running"] {
    --rig-tick-c: var(--primary);
  }

  [data-skin="rig"] [data-control-ui="activity"][data-slot="root"][data-activity-kind="tool"][data-activity-state="error"] {
    --rig-tick-c: oklch(0.5988 0.2021 25.776);
  }

  /* ---- Menu / Select popups: top hairline + row accents ------------------------------------- */

  [data-skin="rig"] [data-control-ui="menu"][data-slot="content"],
  [data-skin="rig"] [data-control-ui="select"][data-slot="content"] {
    border-radius: 0;
    box-shadow:
      0 0 0 1.5px oklch(from var(--foreground) l c h / 0.55),
      inset 0 2px 0 var(--primary);
  }

  [data-skin="rig"] [data-control-ui="menu"][data-slot="item"],
  [data-skin="rig"] [data-control-ui="select"][data-slot="item"] {
    border-radius: 0;
    transition:
      background-color var(--duration-fast) var(--ease-standard),
      box-shadow var(--duration-fast) var(--ease-standard),
      transform var(--duration-fast) var(--ease-standard);
  }

  [data-skin="rig"] [data-control-ui="menu"][data-slot="item"]:hover,
  [data-skin="rig"] [data-control-ui="menu"][data-slot="item"][data-highlighted],
  [data-skin="rig"] [data-control-ui="select"][data-slot="item"]:hover,
  [data-skin="rig"] [data-control-ui="select"][data-slot="item"][data-highlighted] {
    box-shadow: inset 2px 0 0 var(--primary);
    transform: translateX(2px);
  }

  /* ---- Sidebar rows + mono eyebrows ---------------------------------------------------------- */

  [data-skin="rig"] [data-control-ui="sidebar"][data-slot="menu-button"] {
    border-radius: 0;
    transition:
      background-color var(--duration-fast) var(--ease-standard),
      box-shadow var(--duration-fast) var(--ease-standard),
      transform var(--duration-fast) var(--ease-standard);
  }

  [data-skin="rig"] [data-control-ui="sidebar"][data-slot="menu-button"]:hover,
  [data-skin="rig"] [data-control-ui="sidebar"][data-slot="menu-button"][data-active="true"] {
    box-shadow: inset 2px 0 0 var(--primary);
    transform: translateX(2px);
  }

  /* Group labels = mono uppercase eyebrows (matches reference's "DATA EXTRACTION"/"001" style). */
  [data-skin="rig"] [data-control-ui="sidebar"][data-slot="group-label"],
  [data-skin="rig"] [data-control-ui="menu"][data-slot="label"] {
    font-family: var(--font-mono);
    text-transform: uppercase;
    letter-spacing: 0.14em;
    font-weight: 600;
    font-size: 0.68rem;
  }

  /* ---- Tooltip ------------------------------------------------------------------------------- */

  [data-skin="rig"] [data-control-ui="tooltip"][data-slot="content"] {
    border-radius: 0;
    font-family: var(--font-mono);
    letter-spacing: 0.04em;
    box-shadow: 0 0 0 1.5px oklch(from var(--primary) l c h / 0.5);
  }
}

/*
 * Rig owns the complete Control UI token contract: brutalist coral, squared corners, and dense type.
 * Scoped under [data-skin="rig"]; shared @theme bindings remain in Control UI core.
 */

[data-skin="rig"] {
  --font-sans: "Helvetica Neue", "Arial Nova", Arial, "Segoe UI", ui-sans-serif, sans-serif;
  --font-mono: "JetBrains Mono", "IBM Plex Mono", ui-monospace, monospace;

  /* THE one radius knob: 0 squares every control + surface (the chamfer is added in skin.css). */
  --radius: 0px;
  --corner-shape: round;

  --padding-x: 18px;
  --padding-y: 11px;
  --control-h: 40px;

  /* Flat + matte: brutalist controls carry their weight with fill + chamfer, not elevation. */
  --shadow-size: 0;
  --ring-opacity: 1;

  --popover-opacity: 1;
  --backdrop-blur-popover: 0px;
  --overlay-opacity: 0.6;
  --backdrop-blur-overlay: 0px;

  --duration-base: 130ms;
  --duration-fast: 85ms;
  --duration-slow: 210ms;
  --ease-standard: cubic-bezier(0.2, 0, 0, 1);

  --muted: oklch(0.9425 0.0104 79);
  --muted-foreground: oklch(0.5301 0.0224 72);
  --secondary: oklch(0.9425 0.0104 79);
  --accent: oklch(0.9295 0.0118 77);
  --destructive: oklch(0.568 0.1961 32);
  --destructive-foreground: oklch(0.9852 0.0058 85);
  --destructive-text: oklch(from var(--destructive) 0.48 c h);
  --border: oklch(0.8851 0.0135 76 / var(--ring-opacity));
  --input: oklch(0.8851 0.0135 76);
  --ring: oklch(0.6903 0.0198 74);
  --popup-item-foreground: var(--foreground);
  --popup-item-icon-foreground: currentColor;
  --popup-item-highlight-background: oklch(from var(--foreground) l c h / 0.06);
  --badge-neutral: oklch(from var(--foreground) l c h / 0.08);
  --badge-neutral-foreground: var(--foreground);
  --badge-neutral-border: oklch(from var(--foreground) l c h / 0.1);
  --badge-neutral-hover: oklch(from var(--foreground) l c h / 0.12);
  --badge-slate: oklch(from var(--color-slate-500) l c h / 0.14);
  --badge-slate-foreground: var(--color-slate-800);
  --badge-slate-border: oklch(from var(--color-slate-500) l c h / 0.18);
  --badge-slate-hover: oklch(from var(--color-slate-500) l c h / 0.2);
  --badge-gray: oklch(from var(--color-gray-500) l c h / 0.14);
  --badge-gray-foreground: var(--color-gray-800);
  --badge-gray-border: oklch(from var(--color-gray-500) l c h / 0.18);
  --badge-gray-hover: oklch(from var(--color-gray-500) l c h / 0.2);
  --badge-zinc: oklch(from var(--color-zinc-500) l c h / 0.14);
  --badge-zinc-foreground: var(--color-zinc-800);
  --badge-zinc-border: oklch(from var(--color-zinc-500) l c h / 0.18);
  --badge-zinc-hover: oklch(from var(--color-zinc-500) l c h / 0.2);
  --badge-stone: oklch(from var(--color-stone-500) l c h / 0.14);
  --badge-stone-foreground: var(--color-stone-800);
  --badge-stone-border: oklch(from var(--color-stone-500) l c h / 0.18);
  --badge-stone-hover: oklch(from var(--color-stone-500) l c h / 0.2);
  --badge-red: oklch(from var(--color-red-500) l c h / 0.14);
  --badge-red-foreground: var(--color-red-800);
  --badge-red-border: oklch(from var(--color-red-500) l c h / 0.18);
  --badge-red-hover: oklch(from var(--color-red-500) l c h / 0.2);
  --badge-orange: oklch(from var(--color-orange-500) l c h / 0.16);
  --badge-orange-foreground: var(--color-orange-800);
  --badge-orange-border: oklch(from var(--color-orange-500) l c h / 0.2);
  --badge-orange-hover: oklch(from var(--color-orange-500) l c h / 0.24);
  --badge-amber: oklch(from var(--color-amber-400) l c h / 0.2);
  --badge-amber-foreground: var(--color-amber-800);
  --badge-amber-border: oklch(from var(--color-amber-400) l c h / 0.24);
  --badge-amber-hover: oklch(from var(--color-amber-400) l c h / 0.28);
  --badge-yellow: oklch(from var(--color-yellow-400) l c h / 0.2);
  --badge-yellow-foreground: var(--color-yellow-800);
  --badge-yellow-border: oklch(from var(--color-yellow-400) l c h / 0.24);
  --badge-yellow-hover: oklch(from var(--color-yellow-400) l c h / 0.28);
  --badge-lime: oklch(from var(--color-lime-500) l c h / 0.16);
  --badge-lime-foreground: var(--color-lime-800);
  --badge-lime-border: oklch(from var(--color-lime-500) l c h / 0.2);
  --badge-lime-hover: oklch(from var(--color-lime-500) l c h / 0.24);
  --badge-green: oklch(from var(--color-green-500) l c h / 0.16);
  --badge-green-foreground: var(--color-green-800);
  --badge-green-border: oklch(from var(--color-green-500) l c h / 0.2);
  --badge-green-hover: oklch(from var(--color-green-500) l c h / 0.24);
  --badge-emerald: oklch(from var(--color-emerald-500) l c h / 0.16);
  --badge-emerald-foreground: var(--color-emerald-800);
  --badge-emerald-border: oklch(from var(--color-emerald-500) l c h / 0.2);
  --badge-emerald-hover: oklch(from var(--color-emerald-500) l c h / 0.24);
  --badge-teal: oklch(from var(--color-teal-500) l c h / 0.16);
  --badge-teal-foreground: var(--color-teal-800);
  --badge-teal-border: oklch(from var(--color-teal-500) l c h / 0.2);
  --badge-teal-hover: oklch(from var(--color-teal-500) l c h / 0.24);
  --badge-cyan: oklch(from var(--color-cyan-500) l c h / 0.16);
  --badge-cyan-foreground: var(--color-cyan-800);
  --badge-cyan-border: oklch(from var(--color-cyan-500) l c h / 0.2);
  --badge-cyan-hover: oklch(from var(--color-cyan-500) l c h / 0.24);
  --badge-sky: oklch(from var(--color-sky-500) l c h / 0.16);
  --badge-sky-foreground: var(--color-sky-800);
  --badge-sky-border: oklch(from var(--color-sky-500) l c h / 0.2);
  --badge-sky-hover: oklch(from var(--color-sky-500) l c h / 0.24);
  --badge-blue: oklch(from var(--color-blue-500) l c h / 0.16);
  --badge-blue-foreground: var(--color-blue-800);
  --badge-blue-border: oklch(from var(--color-blue-500) l c h / 0.2);
  --badge-blue-hover: oklch(from var(--color-blue-500) l c h / 0.24);
  --badge-indigo: oklch(from var(--color-indigo-500) l c h / 0.16);
  --badge-indigo-foreground: var(--color-indigo-800);
  --badge-indigo-border: oklch(from var(--color-indigo-500) l c h / 0.2);
  --badge-indigo-hover: oklch(from var(--color-indigo-500) l c h / 0.24);
  --badge-violet: oklch(from var(--color-violet-500) l c h / 0.16);
  --badge-violet-foreground: var(--color-violet-800);
  --badge-violet-border: oklch(from var(--color-violet-500) l c h / 0.2);
  --badge-violet-hover: oklch(from var(--color-violet-500) l c h / 0.24);
  --badge-purple: oklch(from var(--color-purple-500) l c h / 0.16);
  --badge-purple-foreground: var(--color-purple-800);
  --badge-purple-border: oklch(from var(--color-purple-500) l c h / 0.2);
  --badge-purple-hover: oklch(from var(--color-purple-500) l c h / 0.24);
  --badge-fuchsia: oklch(from var(--color-fuchsia-500) l c h / 0.16);
  --badge-fuchsia-foreground: var(--color-fuchsia-800);
  --badge-fuchsia-border: oklch(from var(--color-fuchsia-500) l c h / 0.2);
  --badge-fuchsia-hover: oklch(from var(--color-fuchsia-500) l c h / 0.24);
  --badge-pink: oklch(from var(--color-pink-500) l c h / 0.16);
  --badge-pink-foreground: var(--color-pink-800);
  --badge-pink-border: oklch(from var(--color-pink-500) l c h / 0.2);
  --badge-pink-hover: oklch(from var(--color-pink-500) l c h / 0.24);
  --badge-rose: oklch(from var(--color-rose-500) l c h / 0.16);
  --badge-rose-foreground: var(--color-rose-800);
  --badge-rose-border: oklch(from var(--color-rose-500) l c h / 0.2);
  --badge-rose-hover: oklch(from var(--color-rose-500) l c h / 0.24);
  --font-body: var(--font-sans);
  --font-display: var(--font-sans);
  --text-micro: 0.625rem;
  --text-caption: 0.6875rem;
  --text-label: 0.75rem;
  --text-body: 0.875rem;
  --text-body-lg: 1rem;
